//
//  PromoLinkHandler.swift
//  This file defines an ObservableObject to manage the promo data.
//

import Foundation
import Combine

class PromoLinkHandler: ObservableObject {
    @Published var promoCode: String?
    @Published var discount: Int?
    @Published var message: String = "Waiting for promo link..."

    func handle(url: URL) {
        promoCode = nil
        discount = nil
        message = "Processing link..."

        guard url.scheme == "https",
              url.host == "myapp.com",
              url.path == "/promo" else {
            DispatchQueue.main.async {
                self.message = "Invalid universal link format or host mismatch."
            }
            return
        }

        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            DispatchQueue.main.async {
                self.message = "Could not parse URL components."
            }
            return
        }

        var extractedCode: String?
        var extractedDiscount: Int?

        for item in components.queryItems ?? [] {
            switch item.name {
            case "code":
                extractedCode = item.value
            case "discount":
                if let value = item.value, let intValue = Int(value) {
                    extractedDiscount = intValue
                }
            default:
                break
            }
        }

        DispatchQueue.main.async {
            self.promoCode = extractedCode
            self.discount = extractedDiscount

            if let code = extractedCode, let disc = extractedDiscount {
                self.message = "Promo Code '\(code)' with \(disc)% discount applied!"
                // In a real application, you would make an API call here
                // to apply the promo code to the user's account.
                print("Applied Promo Code: \(code), Discount: \(disc)%")
            } else {
                self.message = "Promo link processed, but 'code' or 'discount' parameter was missing."
            }
        }
    }
}


